export enum Tab {
  Home = 'Home',
  Music = 'Music',
  Art = 'Art',
  Tools = 'Tools',
  Gaming = 'Gaming',
  Community = 'Community',
  Library = 'Library',
  About = 'About Us',
}

export enum AboutSideTab {
  WhoWeAre = 'Who We Are',
  MeetTheTeam = 'Meet the Team',
  ContactUs = 'Contact Us',
  SubmitYourWork = 'Submit Your Work',
  JoinOurCrew = 'Join Our Crew',
