// --- Types for Music Page ---

export enum MusicSideTab {
  Introduction = 'Introduction',
  Songs = 'Songs',
  Albums = 'Albums',
  Artists = 'Artists',
  JuelzFM = 'Juelz-FM',
  FilmMusic = 'Film Music',
  GamingMusic = 'Gaming Music',
}

export interface ArtistLink {
  artist: string;
  link: string;
}

export interface AlbumLink {
  album: string;
  song?: string;
  track: number;
  cd: number;
  link: string;
}

// For list views
export interface Song {
  title: string;
  artist: string;
  description: string;
  thumbnail: string;
  link: string;
  genre: string[];
  albums: { album: string; track: number; cd: number, link: string }[];
  soundcloud?: string;
  youtube?: string;
  other_links?: any[];
  featured?: boolean;
  debug?: boolean;
}

export interface Album {
  album: string;
  thumbnail: string;
  link: string;
  genre: string[];
  artists: ArtistLink[];
  tracklist: {
    [cd: string]: {
      number: number;
      title: string;
      artists: ArtistLink[];
      link: string;
      thumbnail: string;
    }[];
  };
  featured?: boolean;
  debug?: boolean;
}

export interface Artist {
  artist: string;
  thumbnail: string;
  link: string;
  genre: string[];
  albums: AlbumLink[];
  featured?: boolean;
  debug?: boolean;
}

export interface MusicPageData {
  intro: string;
  new_releases: any[];
  albums: Album[];
  artists: Artist[];
  songs: Song[];
  juelz_fm: any;
  film_music: any[];
  game_music: any[];
}


// --- Types for Detail Views ---

export interface Link {
  title: string;
  link: string;
}

export type Tag = string;

export type BehindTheScenes = {
  [key: string]: string | string[] | BehindTheScenes;
};

export interface MusicItemCommonDetails {
    release_date: string;
    links?: Link[];
    tags?: Tag[];
    image_gallery?: string[];
    behind_the_scenes?: BehindTheScenes;
}


export interface SongDetail extends MusicItemCommonDetails {
  title: string;
  artist: string;
  artist_links: { name: string; link: string }[];
  thumbnail: string;
  description: string;
  albums: { name: string; link: string; track: number; cd: number }[];
  genres: string[];
  audio: {
    soundcloud_embed?: string;
    youtube_embed?: string;
  };
  lyrics: {
    [key: string]: string;
  };
}

export interface AlbumDetail extends MusicItemCommonDetails {
  title: string;
  artists: string[];
  description: string;
  banner: string;
}

export interface ArtistDetail extends MusicItemCommonDetails {
  artist: string;
  banner_image: string;
  bio: string;
  songs: {
    title: string;
    link: string;
    thumbnail: string;
  }[];
}

export type MusicItemDetail = SongDetail | AlbumDetail | ArtistDetail;

// --- Types for Tools Page ---

export enum ToolsSideTab {
  Introduction = 'Introduction',
  AllTools = 'All Tools',
  WebTools = 'Web Tools',
  WindowsTools = 'Windows Tools',
  Scripts = 'Scripts',
  AITools = 'AI Tools',
}

// For list views
export interface Tool {
  name: string;
  thumbnail: string;
  link: string; // link to detail json
  category: string; // e.g. 'Generators', 'Converters'
  summary: string;
  tags?: string[];
  featured?: boolean;
  debug?: boolean;
  dev?: {
      available: boolean;
      finished: boolean;
  };
}

export interface ToolsByCategory {
    web?: Tool[];
    win?: Tool[];
    scripts?: {
        py?: Tool[];
        ps?: Tool[];
        ahk?: Tool[];
    };
    ai?: {
        tools?: Tool[];
        prompts?: Tool[];
    };
}

export interface ToolsPageData {
  intro: string;
  tools: ToolsByCategory;
}


// --- Types for Tool Detail Views ---

export interface ToolDetailCommon extends MusicItemCommonDetails {
    name: string;
    banner_image?: string;
    summary: string;
    description: string;
}

export interface WebToolDetail extends ToolDetailCommon {
    category: 'Web Tool';
    source_type: 'git' | 'local'; // Differentiates between git-hosted and local apps
    app_path: string; // Path is interpreted based on source_type
}

export interface WindowsToolDetail extends ToolDetailCommon {
    category: 'Windows Tool';
    downloads: {
        version: string;
        path: string; // path to the downloadable file
        release_notes?: string;
    }[];
}

export type ToolDetail = WebToolDetail | WindowsToolDetail;

