// --- Types for Library Page ---
export enum LibrarySideTab {
  Lobby = 'Lobby',
  Aisles = 'Aisles',
  Dictionary = 'Dictionary',
}

export interface LibraryLobby {
  id: string;
  title: string;
  image: string;
  subtitle: string;
  welcome: string;
  what_its_for: string;
  what_it_covers: string;
  document_types: string[];
  adding_documents: string;
}

// From .mpo files
export interface LibraryPost {
    meta: any;
    cfg: {
        title: string;
        subtitle?: string;
        [key: string]: any;
    };
}

// From .mld files
export interface Skillset {
    name: string;
    id: string;
    desc: string;
    levels: { name: string; desc: string; example: string }[];
    difficulties: { name: string; desc: string; example: string }[];
    [key: string]: any;
}

export interface DictionaryCollection {
    name: string;
    id: string;
    s_set?: string;
    desc: string;
    terms: any[];
    categories: any[];
}

export interface DictionaryData {
    desc?: string[];
    skillsets?: Skillset[];
    collections?: DictionaryCollection[];
}

export interface MasterDictionary {
    dictionary: DictionaryData;
    errors?: string[];
}

// Represents a file or folder in the library
export interface LibraryContentItem {
    name: string;
    path: string;
    type: 'file' | 'dir';
    children?: LibraryContentItem[];
    meta?: LibraryPost; // for folders, from .mpo file
}

export interface LibraryPageData {
  lobby: LibraryLobby;
  aisles: LibraryContentItem | null; // This will be the root of the library file structure
  dictionary: MasterDictionary | null; // This will be the merged dictionary
  error?: string;
}

