                <h2 className="text-4xl font-extrabold text-amber-400">{title}</h2>
                <p className="text-gray-400 mt-2">Explore the sub-categories within this section.</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {subSections.map(({ id, section }) => {
                      if (!section) return null;
                      return (
                        <div 
                            key={id}
                            onClick={() => setActiveTab(id)}
                            className="bg-gray-900/50 backdrop-blur-lg rounded-2xl overflow-hidden ring-1 ring-white/10 shadow-xl group cursor-pointer hover:ring-amber-500/50 transition-all duration-300 flex flex-col"
                        >
                            <div className="h-40 overflow-hidden relative">
                                <GitHubImage 
                                    manifest={manifest}
                                    path={section.thumbnail || ''}
                                    alt={section.name || id}
                                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                                    placeholderCat="gaming"
                                />
                                <div className="absolute inset-0 bg-gradient-to-t from-gray-900 via-transparent to-transparent opacity-60" />
                            </div>
                            <div className="p-6 flex-grow">
                                <h3 className="text-2xl font-bold text-amber-300 mb-2 group-hover:text-amber-400 transition-colors">{section.name || id}</h3>
                                <p className="text-gray-300 text-sm leading-relaxed line-clamp-3">
                                    {section.summary || "Explore projects, mods, and tools in this category."}
                                </p>
                            </div>
                            <div className="px-6 pb-6 mt-auto">
                                <span className="text-amber-400 text-xs font-black uppercase tracking-widest group-hover:translate-x-1 inline-block transition-transform">
                                    Browse Section &rarr;
                                </span>
                            </div>
                        </div>
                      );
                  })}
              </div>
          </div>
      )
  }

  const renderSection = (section: GamingSection | undefined, title?: string) => {
    if (!section) return null;

    const filteredGames = (section.games || []).filter(item => showDebugContent || !item.debug);
    const filteredMods = (section.mods || []).filter(item => showDebugContent || !item.debug);
    const filteredServers = (section.servers || []).filter(item => showDebugContent || !item.debug);
    const filteredAssets = (section.assets || []).filter(item => showDebugContent || !item.debug);
    const filteredTools = (section.tools || []).filter(item => showDebugContent || !item.debug);

    const hasContent = filteredGames.length > 0 || filteredMods.length > 0 || filteredServers.length > 0 || filteredAssets.length > 0 || filteredTools.length > 0;

    if (!hasContent && !section.introduction) {
        return (
            <div className="text-center py-20 bg-gray-900/30 rounded-2xl border border-dashed border-white/10">
                <p className="text-gray-500 font-medium italic">No content has been added to this section yet. Check back soon!</p>
            </div>
        );
    }

    return (
      <div className="space-y-8 mb-12 animate-fade-in-up">
        {title && <h2 className="text-3xl font-bold text-amber-400 mb-4 border-b-2 border-white/10 pb-2">{title}</h2>}

        {section.introduction && (
          <div className="prose prose-invert max-w-none mb-6">
            <MarkdownRenderer markdown={section.introduction} />
          </div>
        )}

        {filteredGames.length > 0 && (
          <div>
            <h3 className="text-xl font-bold text-amber-300 mb-4">Games</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredGames.map(item => (
                <GamingCard key={item.link} item={item} type="game" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        )}

        {filteredMods.length > 0 && (
          <div>
            <h3 className="text-xl font-bold text-amber-300 mb-4">Mods</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredMods.map(item => (
                <GamingCard key={item.link} item={item} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        )}

        {filteredServers.length > 0 && (
          <div>
            <h3 className="text-xl font-bold text-amber-300 mb-4">Servers</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredServers.map(item => (
                <GamingCard key={item.link} item={item} type="server" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        )}

        {filteredAssets.length > 0 && (
          <div>
            <h3 className="text-xl font-bold text-amber-300 mb-4">Assets</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredAssets.map(item => (
                 <GamingCard key={item.link} item={{ ...item, genre: [item.type], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        )}

        {filteredTools.length > 0 && (
          <div>
            <h3 className="text-xl font-bold text-amber-300 mb-4">Development Tools</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredTools.map(item => (
                 <GamingCard key={item.link} item={{ ...item, genre: [item.type || 'Tool'], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderContent = () => {
    switch (activeTab) {
      case GamingSideTab.Introduction:
        return <IntroductionTab htmlContent={data.intro} />;

      case GamingSideTab.UE5:
        return renderSection(data.ue5, "Unreal Engine 5");

      case GamingSideTab.Unity:
        return renderSection(data.unity, "Unity");

      // GTA Category
      case GamingSideTab.GTA:
        return renderCategoryDashboard("GTA Modding Hub", [
            { id: GamingSideTab.GTA_FiveM, section: data.gta?.fivem },
            { id: GamingSideTab.GTA_V, section: data.gta?.gta5 },
            { id: GamingSideTab.GTA_IV, section: data.gta?.iv },
        ]);
      case GamingSideTab.GTA_FiveM: return renderSection(data.gta?.fivem, "FiveM (GTA)");
      case GamingSideTab.GTA_V: return renderSection(data.gta?.gta5, "Grand Theft Auto V");
      case GamingSideTab.GTA_IV: return renderSection(data.gta?.iv, "Grand Theft Auto IV");

      // Valve Category
      case GamingSideTab.Valve:
        return renderCategoryDashboard("Valve & Source Engine", [
            { id: GamingSideTab.Valve_GMod, section: data.valve?.gmod },
            { id: GamingSideTab.Valve_Wire, section: data.valve?.wire },
        ]);
      case GamingSideTab.Valve_GMod: return renderSection(data.valve?.gmod, "Garry's Mod");
      case GamingSideTab.Valve_Wire: return renderSection(data.valve?.wire, "Wiremod");

      case GamingSideTab.Roblox:
        return renderSection(data.roblox, "Roblox");

      case GamingSideTab.Web:
        return renderSection(data.web, "Web Games");

      case GamingSideTab.Other:
        return renderSection(data.other, "Miscellaneous");

      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
      <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
        <SideNav<GamingSideTab> tabs={gamingNav} activeTab={activeTab} setActiveTab={setActiveTab} />
      </aside>
      <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
        <div className="px-4 sm:px-6 lg:px-8 pb-28">
          {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default GamingPage;

