import React, { useState } from 'react';
import ReactMarkdown, { Components } from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkBreaks from 'remark-breaks';
import rehypeRaw from 'rehype-raw';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { Manifest } from '../services/contentService';

interface MarkdownRendererProps {
  markdown: string;
  className?: string;
  inline?: boolean;
  manifest?: Manifest | null;
}

const CopyIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
    </svg>
);

const CheckIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
    </svg>
);

const CustomCodeComponent: React.FC<any> = ({ node, inline, className, children, ...props }) => {
    const [copyStatus, setCopyStatus] = useState<'idle' | 'copied'>('idle');
    const match = /language-(\w+)/.exec(className || '');
    const language = match ? match[1] : 'text';
    const codeString = String(children).replace(/\n$/, '');

    const handleCopy = () => {
        navigator.clipboard.writeText(codeString).then(() => {
            setCopyStatus('copied');
            setTimeout(() => setCopyStatus('idle'), 2000);
        });
    };

    return !inline ? (
        <div className="code-block-wrapper relative group bg-gray-900/70 rounded-lg ring-1 ring-white/10 my-4 overflow-hidden">
            <div className="flex justify-between items-center px-4 py-1.5 bg-gray-800/50 border-b border-white/10">
                <span className="text-xs font-semibold text-amber-300 uppercase tracking-wider">{language}</span>
                <button
                    onClick={handleCopy}
                    className="flex items-center gap-1.5 px-2 py-1 text-xs font-semibold text-gray-300 bg-gray-700/50 rounded-md hover:bg-gray-700 transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100"
                    aria-label="Copy code to clipboard"
                >
                    {copyStatus === 'idle' ? <CopyIcon /> : <CheckIcon />}
                    {copyStatus === 'idle' ? 'Copy' : 'Copied!'}
                </button>
            </div>
            <SyntaxHighlighter
                {...props}
                style={atomDark}
                language={language}
                showLineNumbers
                wrapLines={true}
                customStyle={{ margin: 0, backgroundColor: 'transparent' }}
            >
                {codeString}
            </SyntaxHighlighter>
        </div>
    ) : (
        <code {...props}>{children}</code>
    );
};

const CustomTable: React.FC<React.TableHTMLAttributes<HTMLTableElement>> = ({ node, ...props }: any) => (
    <div className="markdown-table-card">
        <table {...props} />
    </div>
);

const CustomHr: React.FC = () => <hr className="custom-hr" />;

const CustomA: React.FC<React.AnchorHTMLAttributes<HTMLAnchorElement>> = ({ node, ...props }: any) => (
    <a target="_blank" rel="noopener noreferrer" className="text-amber-400 hover:text-amber-200 underline decoration-amber-500/30 transition-colors" {...props} />
);

const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ markdown, className, inline = false, manifest }) => {
  if (!markdown) return null;

  const components: Components = {
    p: inline ? React.Fragment : 'p',
    code: CustomCodeComponent,
    table: CustomTable,
    hr: CustomHr,
    a: CustomA,
    img: ({ src, alt, title, ...props }) => {
        let finalSrc = src;
        // If path is relative and we have manifest, resolve it to GitHub Raw
        if (src && !src.startsWith('http') && manifest) {
            const { user, repo, branch } = manifest.git;
            finalSrc = `https://raw.githubusercontent.com/${user}/${repo}/${branch}/${src.startsWith('/') ? src.slice(1) : src}`;
        }
        return <img src={finalSrc} alt={alt} title={title} loading="lazy" {...props} />;
    }
  };

  return (
    <div className={`prose prose-invert max-w-none ${className}`}>
        <ReactMarkdown
            components={components}
            remarkPlugins={[remarkGfm, remarkBreaks]}
            rehypePlugins={[rehypeRaw]}
        >
            {markdown}
        </ReactMarkdown>
    </div>
  );
};

export default MarkdownRenderer;

import React, { useState, useEffect } from 'react';
import { LibraryContentItem } from '../../types';
import { Manifest } from '../../services/contentService';
import { fetchFromGitHubRaw } from '../../modules/io/import-utils';
import MarkdownRenderer from '../MarkdownRenderer';

interface MarkdownViewerProps {
    file: LibraryContentItem;
    manifest: Manifest | null;
    onBack: () => void;
}

const MarkdownViewer: React.FC<MarkdownViewerProps> = ({ file, manifest, onBack }) => {
    const [content, setContent] = useState<string>('');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!manifest) {
            setError('Manifest not available.');
            setIsLoading(false);
            return;
        }

        const loadContent = async () => {
            setIsLoading(true);
            setError(null);
            try {
                const { user, repo, branch } = manifest.git;
                const fileContent = await fetchFromGitHubRaw(user, repo, branch, file.path);
                setContent(fileContent);
            } catch (err) {
                setError(err instanceof Error ? err.message : 'Failed to load file content.');
            } finally {
                setIsLoading(false);
            }
        };

        loadContent();
    }, [file, manifest]);

    return (
        <div className="p-4 sm:p-6 bg-gray-900/50 backdrop-blur-lg rounded-2xl shadow-2xl ring-1 ring-white/10">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold text-amber-400 truncate">{file.name}</h2>
                <button
                    onClick={onBack}
                    className="px-4 py-2 text-sm font-semibold bg-amber-500/90 text-gray-900 rounded-lg hover:bg-amber-500 transition-colors flex items-center gap-2"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M12.707 5.293a1 1 0 010 1.414L9.414 10l3.293 3.293a1 1 0 01-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                    Back
                </button>
            </div>

            <div className="bg-black/20 p-4 rounded-md overflow-x-auto min-h-[400px]">
                {isLoading && <div className="flex flex-col items-center justify-center py-20"><div className="w-8 h-8 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" /><p className="text-amber-400 font-mono text-xs uppercase tracking-widest">Parsing Document...</p></div>}
                {error && <p className="text-red-400">Error: {error}</p>}
                {!isLoading && !error && (
                   <MarkdownRenderer markdown={content} manifest={manifest} />
                )}
            </div>
        </div>
    );
};

export default MarkdownViewer;

