// components/music/IntroductionTab.tsx
import React, { useState } from 'react';
import MarkdownRenderer from '../MarkdownRenderer';
import SectionPanel from '../SectionPanel';
import MusicCard from './MusicCard';
import ToolCard from '../tools/ToolCard';
import GamingCard from '../gaming/GamingCard';
import ArtCard from '../art/ArtCard';
import CommunityCard from '../community/CommunityCard';
import { Manifest } from '../../services/contentService';

interface IntroductionTabProps {
  htmlContent: string;
  newItems?: any[];
  manifest: Manifest | null;
  onViewDetails?: (link: string) => void;
  onNavigate?: (tab: any, id: string) => void;
  onLaunch?: (link: string) => void;
  pageType?: 'music' | 'gaming' | 'art' | 'tools' | 'community';
}

const IntroductionTab: React.FC<IntroductionTabProps> = ({ 
    htmlContent, 
    newItems = [], 
    manifest, 
    onViewDetails, 
    onNavigate, 
    onLaunch,
    pageType 
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const hasNewItems = newItems.length > 0;

  const renderCard = (item: any) => {
      const handleViewDetails = (link: string) => onViewDetails?.(link);

      switch (pageType) {
          case 'music':
              // Determine music type based on keys
              const mType = item.title ? 'song' : (item.album ? 'album' : 'artist');
              return <MusicCard item={item} type={mType as any} manifest={manifest} onNavigate={onNavigate || (() => {})} onViewDetails={handleViewDetails} size="small" />;
          case 'tools':
              return <ToolCard item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => onLaunch?.(item.link)} />;
          case 'gaming':
              // Determine gaming type
              const gType = item.platform ? 'game' : (item.ip_address ? 'server' : 'mod');
              return <GamingCard item={item} type={gType as any} manifest={manifest} onViewDetails={handleViewDetails} />;
          case 'art':
              const aType = item.medium ? 'piece' : 'artist';
              return <ArtCard item={item} type={aType as any} manifest={manifest} onViewDetails={handleViewDetails} />;
          case 'community':
              const cType = item.subjects ? 'person' : 'event';
              return <CommunityCard item={item} type={cType as any} manifest={manifest} onViewDetails={handleViewDetails} />;
          default:
              return null;
      }
  };

  return (
    <div className="space-y-6">
        <SectionPanel className="glow-on-hover glow-dark-primary">
            <MarkdownRenderer markdown={htmlContent} />
        </SectionPanel>

        {hasNewItems && (
            <div className={`bg-gray-900/50 backdrop-blur-lg rounded-2xl ring-1 transition-all duration-500 overflow-hidden shadow-2xl ${isExpanded ? 'ring-amber-500/40' : 'ring-white/10 hover:ring-amber-500/20'}`}>
                <button 
                    onClick={() => setIsExpanded(!isExpanded)}
                    className="w-full flex items-center justify-between p-5 text-left transition-colors hover:bg-white/5"
                >
                    <div className="flex items-center gap-4">
                        <div className="relative">
                            <h3 className="text-xl font-bold text-amber-400">Latest Releases</h3>
                            <span className="absolute -top-1 -right-3 flex h-2 w-2">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-amber-500"></span>
                            </span>
                        </div>
                        <span className="px-2 py-0.5 bg-amber-500/20 text-amber-200 text-[10px] font-black uppercase rounded border border-amber-500/30">
                            {newItems.length} New
                        </span>
                    </div>
                    <div className={`text-amber-500 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                        </svg>
                    </div>
                </button>

                <div className={`transition-all duration-500 ease-in-out ${isExpanded ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                    <div className="p-6 pt-0">
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {newItems.map((item, i) => (
                                <div key={item.link || i} className="animate-fade-in-up" style={{ animationDelay: `${i * 100}ms` }}>
                                    {renderCard(item)}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default IntroductionTab;

