  manifest: Manifest | null;
  showDebugContent: boolean;
}

const musicNav: NavItem<MusicSideTab>[] = [
  { id: MusicSideTab.Introduction, label: 'Introduction' },
  { id: MusicSideTab.Songs, label: 'Songs' },
  { id: MusicSideTab.Albums, label: 'Albums' },
  { id: MusicSideTab.Artists, label: 'Artists' },
  { 
    id: MusicSideTab.JuelzFM, 
    label: 'Juelz-FM',
    children: [
        { id: MusicSideTab.JuelzFM_Live, label: 'Live Stream' },
        { id: MusicSideTab.JuelzFM_Schedule, label: 'Broadcast Schedule' },
        { id: MusicSideTab.JuelzFM_Archives, label: 'Archive Vault' },
    ]
  },
  { 
    id: MusicSideTab.FilmMusic, 
    label: 'Film Music',
    children: [
        { id: MusicSideTab.Film_TheVoid, label: 'The Void' },
        { id: MusicSideTab.Film_NeonNights, label: 'Neon Nights' },
    ]
  },
  { 
    id: MusicSideTab.GamingMusic, 
    label: 'Gaming Music',
    children: [
        { id: MusicSideTab.Game_LoFiRunner, label: 'Lo-Fi Runner' },
        { id: MusicSideTab.Game_ZikyQuest, label: 'Ziky Quest' },
    ]
  },
];

const SESSION_STORAGE_KEY = 'zikyinc_music_active_tab';

const MusicPage: React.FC<MusicPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<MusicSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    // Explicitly validate saved tab against enum values
    if (savedTab && Object.values(MusicSideTab).includes(savedTab as MusicSideTab)) {
        return savedTab as MusicSideTab;
    }
    return MusicSideTab.Introduction;
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [genreFilter, setGenreFilter] = useState('All');
  const [viewMode, setViewMode] = useState<ViewMode>('card');

  // State for Detail View
  const [selectedItemLink, setSelectedItemLink] = useState<string | null>(null);
  const [detailData, setDetailData] = useState<MusicItemDetail | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  useEffect(() => {
    if (!selectedItemLink || !manifest) return;

    const fetchDetailData = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const { user, repo, branch } = manifest.git;
        const content = await fetchFromGitHubRaw(user, repo, branch, selectedItemLink);
        setDetailData(JSON.parse(content));
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    fetchDetailData();
  }, [selectedItemLink, manifest]);

  const handleNavigateToList = useCallback((tab: MusicSideTab, id: string) => {
    setActiveTab(tab);
    setSelectedItemLink(null);
    setSearchTerm(''); 
    setGenreFilter('All');
  }, []);

  const handleNavigateToDetail = useCallback((link: string) => setSelectedItemLink(link), []);
  const handleViewDetails = useCallback((link: string) => setSelectedItemLink(link), []);
  const handleBackToList = useCallback(() => { setSelectedItemLink(null); setDetailData(null); }, []);

  const allGenres = useMemo(() => {
    const genres = new Set<string>();
    (data.songs || []).forEach(s => (s.genre || []).forEach(g => genres.add(g)));
    (data.albums || []).forEach(a => (a.genre || []).forEach(g => genres.add(g)));
    (data.artists || []).forEach(a => (a.genre || []).forEach(g => genres.add(g)));
    return ['All', ...Array.from(genres).sort()];
  }, [data]);

  const newMusicItems = useMemo(() => {
      if (!data) return [];
      const items: any[] = [];
      const filter = (arr: any[]) => arr.filter(item => item.new === true);
      items.push(...filter(data.songs || []));
      items.push(...filter(data.albums || []));
      items.push(...filter(data.artists || []));
      return items;
  }, [data]);

  /**
   * Helper to find nested nav items
   */
  const findNavItem = (id: MusicSideTab, items: NavItem<MusicSideTab>[] = musicNav): NavItem<MusicSideTab> | undefined => {
      for (const item of items) {
          if (item.id === id) return item;
          if (item.children) {
              const found = findNavItem(id, item.children);
              if (found) return found;
          }
      }
      return undefined;
  };

  /**
   * Resolves metadata for Dashboards
   */
  const getSectionData = useCallback((id: MusicSideTab): any => {
      if (!data) return {};
      switch (id) {
          case MusicSideTab.JuelzFM: return data.juelz_fm?.root || {};
          case MusicSideTab.JuelzFM_Live: return data.juelz_fm?.live || { name: 'FM Live', summary: 'Listen to the underground 24/7.' };
          case MusicSideTab.JuelzFM_Schedule: return data.juelz_fm?.schedule || { name: 'Broadcast Schedule', summary: 'Never miss a beat.' };
          case MusicSideTab.JuelzFM_Archives: return data.juelz_fm?.archives || { name: 'Archives', summary: 'Relive the highlights.' };
          case MusicSideTab.FilmMusic: return data.film_music?.root || {};
          case MusicSideTab.GamingMusic: return data.game_music?.root || {};
          default:
              if (data.film_music?.projects[id]) return data.film_music.projects[id];
              if (data.game_music?.projects[id]) return data.game_music.projects[id];
              return {};
      }
  }, [data]);

  const renderListContent = (featuredItems: any[], allItems: any[], type: 'song' | 'album' | 'artist') => (
    <div className="space-y-6">
      <div className="sticky top-2 z-10 flex justify-end -mr-2">
        <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
          <SearchAndFilter searchTerm={searchTerm} setSearchTerm={setSearchTerm} activeFilter={genreFilter} setActiveFilter={setGenreFilter} filterOptions={allGenres} filterTypeLabel="Genre" />
          <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
        </div>
      </div>
      {featuredItems.length > 0 && (
        <div>
          <h2 className="text-2xl font-bold text-amber-300 mb-4 border-b-2 border-white/10 pb-2">Featured</h2>
          <div className="conveyor-scrollbar -mx-2 sm:-mx-4 lg:-mx-6 px-2 sm:px-4 lg:px-6 pb-4 overflow-x-auto"><div className="flex flex-nowrap gap-6">{featuredItems.map((item: any) => (<div key={item.link} className="w-48 flex-shrink-0 h-full"><MusicCard item={item} type={type} manifest={manifest} onNavigate={handleNavigateToList} onViewDetails={handleViewDetails} size="small" /></div>))}</div></div>
        </div>
      )}
      {allItems.length > 0 ? (
         <div className={featuredItems.length > 0 ? "pt-6" : ""}>
             {viewMode === 'card' && <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{allItems.map((item: any) => <MusicCard key={item.link} item={item} type={type} manifest={manifest} onNavigate={handleNavigateToList} onViewDetails={handleViewDetails} />)}</div>}
             {viewMode === 'list' && <ListView items={allItems} type={type} manifest={manifest} onViewDetails={handleViewDetails} />}
             {viewMode === 'conveyor' && <ConveyorView items={allItems} type={type} manifest={manifest} onNavigate={handleNavigateToList} onViewDetails={handleViewDetails} />}
         </div>
      ) : <div className="text-center py-10"><p className="text-gray-400">No {type}s found.</p></div>}
    </div>
  );

  const renderContent = () => {
    if (selectedItemLink) return <ItemDetailView data={detailData} isLoading={isLoadingDetail} error={detailError} onBack={handleBackToList} onNavigateToDetail={handleNavigateToDetail} manifest={manifest} />;

    const navItem = findNavItem(activeTab);

    // 1. Handle Dashboards for Roots (If it has children but no specific component logic)
    if (navItem?.children && navItem.children.length > 0 && 
        activeTab !== MusicSideTab.JuelzFM && 
        activeTab !== MusicSideTab.FilmMusic && 
        activeTab !== MusicSideTab.GamingMusic) {
        const pData = getSectionData(activeTab);
        return <CategoryDashboard title={navItem.label} subtitle={pData.summary} items={navItem.children} onItemClick={(id) => setActiveTab(id)} manifest={manifest} dataMapper={(id) => getSectionData(id)} />;
    }

    // 2. Handle Juelz-FM Hierarchy
    const isJuelzTab = activeTab === MusicSideTab.JuelzFM || 
                       activeTab === MusicSideTab.JuelzFM_Live || 
                       activeTab === MusicSideTab.JuelzFM_Schedule || 
                       activeTab === MusicSideTab.JuelzFM_Archives;

    if (isJuelzTab) {
        let blockData = data.juelz_fm?.root;
        if (activeTab === MusicSideTab.JuelzFM_Live) blockData = data.juelz_fm?.live;
        if (activeTab === MusicSideTab.JuelzFM_Schedule) blockData = data.juelz_fm?.schedule;
        if (activeTab === MusicSideTab.JuelzFM_Archives) blockData = data.juelz_fm?.archives;
        return blockData ? <DynamicLayout data={blockData} /> : <div className="p-8 text-center text-gray-500">Juelz-FM Section content missing in data.</div>;
    }

    // 3. Handle OST Project Albums
    const isFilmOST = data.film_music?.projects[activeTab];
    const isGameOST = data.game_music?.projects[activeTab];
    if (isFilmOST || isGameOST) {
        const album = isFilmOST || isGameOST;
        return (
            <div className="animate-fade-in-up">
                <header className="mb-8 border-b-2 border-amber-500/20 pb-4">
                    <h1 className="text-4xl font-bold text-amber-400">{album.album}</h1>
                    <p className="text-amber-200">{album.genre.join(', ')}</p>
                </header>
                <div className="max-w-md">
                    <MusicCard item={album} type="album" manifest={manifest} onNavigate={handleNavigateToList} onViewDetails={handleViewDetails} />
                </div>
            </div>
        );
    }

    // 4. Handle Root Hubs for Film/Game (Dashboard)
    if (activeTab === MusicSideTab.FilmMusic || activeTab === MusicSideTab.GamingMusic) {
        const pData = getSectionData(activeTab);
        return <CategoryDashboard title={navItem?.label || ''} subtitle={pData.summary} items={navItem?.children || []} onItemClick={(id) => setActiveTab(id)} manifest={manifest} dataMapper={(id) => getSectionData(id)} />;
    }

    // 5. Default List View Tabs
    switch (activeTab) {
      case MusicSideTab.Introduction: return <IntroductionTab htmlContent={data.intro} newItems={newMusicItems} manifest={manifest} onViewDetails={handleViewDetails} onNavigate={handleNavigateToList} pageType="music" />;
      case MusicSideTab.Songs: return renderListContent(data.songs.filter(s => s.featured), data.songs, 'song');
      case MusicSideTab.Albums: return renderListContent(data.albums.filter(a => a.featured), data.albums, 'album');
      case MusicSideTab.Artists: return renderListContent(data.artists.filter(a => a.featured), data.artists, 'artist');
      default: return <div className="p-10 text-center text-gray-500">Select a section to view content.</div>;
    }
  };

  if (!data) return <div className="p-8 text-center text-amber-400 font-bold">Music content unavailable.</div>;

  return (
    <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
      <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
        <SideNav<MusicSideTab> tabs={musicNav} activeTab={activeTab} setActiveTab={setActiveTab} />
      </aside>
      <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
        <div className="px-4 sm:px-6 lg:px-8 pb-28">
          {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default MusicPage;

// pages/GamingPage.tsx
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { GamingPageData, GamingSideTab, NavItem, GamingSection } from '../types';
import { Manifest } from '../services/contentService';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import GamingCard from '../components/gaming/GamingCard';
import MarkdownRenderer from '../components/MarkdownRenderer';
import CategoryDashboard from '../components/CategoryDashboard';

interface GamingPageProps {
  data: GamingPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const gamingNav: NavItem<GamingSideTab>[] = [
  { id: GamingSideTab.Introduction, label: 'Introduction' },
  { 
    id: GamingSideTab.UE5, 
    label: 'UE5 Projects',
    children: [
        { id: GamingSideTab.UE5_Games, label: 'Games' },
        { id: GamingSideTab.UE5_Assets, label: 'Assets' },
        { id: GamingSideTab.UE5_Tools, label: 'Tools' },
    ]
  },
  { 
    id: GamingSideTab.Unity, 
    label: 'Unity Projects',
    children: [
        { id: GamingSideTab.Unity_Games, label: 'Games' },
        { id: GamingSideTab.Unity_Assets, label: 'Assets' },
        { id: GamingSideTab.Unity_Tools, label: 'Tools' },
    ]
  },
  { 
    id: GamingSideTab.GTA, 
    label: 'GTA Modding',
    children: [
        { 
            id: GamingSideTab.GTA_FiveM, 
            label: 'FiveM',
            children: [
                { id: GamingSideTab.GTA_FiveM_Servers, label: 'Servers' },
                { id: GamingSideTab.GTA_FiveM_Assets, label: 'Assets' },
                { id: GamingSideTab.GTA_FiveM_Tools, label: 'Tools' },
            ]
        },
        { 
            id: GamingSideTab.GTA_V, 
            label: 'GTA V (SP)',
            children: [
                { id: GamingSideTab.GTA_V_Mods, label: 'Mods' },
                { id: GamingSideTab.GTA_V_Scripts, label: 'Scripts' },
            ]
        },
        { 
            id: GamingSideTab.GTA_IV, 
            label: 'GTA IV',
            children: [
                { id: GamingSideTab.GTA_IV_Mods, label: 'Mods' },
                { id: GamingSideTab.GTA_IV_Scripts, label: 'Scripts' },
            ]
        },
    ]
  },
  { 
    id: GamingSideTab.Valve, 
    label: 'Valve / Source',
    children: [
        { 
            id: GamingSideTab.Valve_GMod, 
            label: 'Garry\'s Mod',
            children: [
                { id: GamingSideTab.Valve_GMod_Mods, label: 'Mods' },
                { id: GamingSideTab.Valve_GMod_Maps, label: 'Maps' },
            ]
        },
        { 
            id: GamingSideTab.Valve_Wire, 
            label: 'Wiremod',
            children: [
                { id: GamingSideTab.Valve_Wire_Tools, label: 'Wire Tools' },
                { id: GamingSideTab.Valve_Wire_Scripts, label: 'Scripts (E2)' },
            ]
        },
    ]
  },
  { id: GamingSideTab.Roblox, label: 'Roblox' },
  { id: GamingSideTab.Web, label: 'Web Games' },
  { id: GamingSideTab.Other, label: 'Other Projects' },
];

const SESSION_STORAGE_KEY = 'zikyinc_gaming_active_tab';

const GamingPage: React.FC<GamingPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<GamingSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    return (savedTab as GamingSideTab) || GamingSideTab.Introduction;
  });

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const handleViewDetails = (link: string) => {
    console.log('Viewing details for:', link);
  };

  /**
   * Helper to find nested nav items
   */
  const findNavItem = (id: GamingSideTab, items: NavItem<GamingSideTab>[] = gamingNav): NavItem<GamingSideTab> | undefined => {
      for (const item of items) {
          if (item.id === id) return item;
          if (item.children) {
              const found = findNavItem(id, item.children);
              if (found) return found;
          }
      }
      return undefined;
  };

  const newGamingItems = useMemo(() => {
      if (!data) return [];
      const items: any[] = [];
      const filterNew = (section?: GamingSection) => {
          if (!section) return;
          const check = (arr?: any[]) => (arr || []).filter(i => i.new === true);
          items.push(...check(section.games));
          items.push(...check(section.mods));
          items.push(...check(section.assets));
          items.push(...check(section.servers));
          items.push(...check(section.tools));
          items.push(...check(section.scripts));
          items.push(...check(section.maps));
      };

      filterNew(data.ue5);
      filterNew(data.unity);
      filterNew(data.roblox);
      filterNew(data.web);
      filterNew(data.other);

      if (data.gta) {
          filterNew(data.gta.fivem);
          filterNew(data.gta.gta5);
          filterNew(data.gta.iv);
      }

      if (data.valve) {
          filterNew(data.valve.gmod);
          filterNew(data.valve.wire);
      }

      return items;
  }, [data]);

  /**
   * Simple mapper to get data from the JSON based on the tab ID.
   */
  const getSectionData = useCallback((id: GamingSideTab): { name?: string; thumbnail?: string; summary?: string; content?: GamingSection } => {
    if (!data) return {};

    const getFunctionalMeta = (typeName: string) => ({
        name: typeName,
        thumbnail: 'Website/img/logos/ZIKYinc_DevLogo.png',
        summary: `Explore the collection of ${typeName.toLowerCase()} in this section.`
    });

    switch (id) {
        // Roots
        case GamingSideTab.UE5: return { ...data.ue5, content: data.ue5 };
        case GamingSideTab.Unity: return { ...data.unity, content: data.unity };
        case GamingSideTab.GTA: return data.gta || {};
        case GamingSideTab.Valve: return data.valve || {};
        case GamingSideTab.Roblox: return { ...data.roblox, content: data.roblox };
        case GamingSideTab.Web: return { ...data.web, content: data.web };
        case GamingSideTab.Other: return { ...data.other, content: data.other };

        // Sub-categories
        case GamingSideTab.GTA_FiveM: return { ...data.gta?.fivem, content: data.gta?.fivem };
        case GamingSideTab.GTA_V: return { ...data.gta?.gta5, content: data.gta?.gta5 };
        case GamingSideTab.GTA_IV: return { ...data.gta?.iv, content: data.gta?.iv };
        case GamingSideTab.Valve_GMod: return { ...data.valve?.gmod, content: data.valve?.gmod };
        case GamingSideTab.Valve_Wire: return { ...data.valve?.wire, content: data.valve?.wire };

        // Functional Sections
        case GamingSideTab.UE5_Games: return getFunctionalMeta('UE5 Games');
        case GamingSideTab.UE5_Assets: return getFunctionalMeta('UE5 Assets');
        case GamingSideTab.UE5_Tools: return getFunctionalMeta('UE5 Tools');
        case GamingSideTab.Unity_Games: return getFunctionalMeta('Unity Games');
        case GamingSideTab.Unity_Assets: return getFunctionalMeta('Unity Assets');
        case GamingSideTab.Unity_Tools: return getFunctionalMeta('Unity Tools');
        case GamingSideTab.GTA_FiveM_Servers: return getFunctionalMeta('FiveM Servers');
        case GamingSideTab.GTA_FiveM_Assets: return getFunctionalMeta('FiveM Assets');
        case GamingSideTab.GTA_FiveM_Tools: return getFunctionalMeta('FiveM Tools');
        case GamingSideTab.GTA_V_Mods: return getFunctionalMeta('GTA V Mods');
        case GamingSideTab.GTA_V_Scripts: return getFunctionalMeta('GTA V Scripts');
        case GamingSideTab.GTA_IV_Mods: return getFunctionalMeta('GTA IV Mods');
        case GamingSideTab.GTA_IV_Scripts: return getFunctionalMeta('GTA IV Scripts');
        case GamingSideTab.Valve_GMod_Mods: return getFunctionalMeta('GMod Mods');
        case GamingSideTab.Valve_GMod_Maps: return getFunctionalMeta('GMod Maps');
        case GamingSideTab.Valve_Wire_Tools: return getFunctionalMeta('Wire Tools');
        case GamingSideTab.Valve_Wire_Scripts: return getFunctionalMeta('Wire Scripts');

        default: return {};
    }
  }, [data]);

  const renderSection = (section: GamingSection | undefined, title?: string, subSectionFilter?: keyof GamingSection) => {
    if (!section) return null;

    const filter = (items: any[] | undefined) => (items || []).filter(item => showDebugContent || !item.debug);

    const filteredGames = subSectionFilter === 'games' || !subSectionFilter ? filter(section.games) : [];
    const filteredMods = subSectionFilter === 'mods' || !subSectionFilter ? filter(section.mods) : [];
    const filteredServers = subSectionFilter === 'servers' || !subSectionFilter ? filter(section.servers) : [];
    const filteredAssets = subSectionFilter === 'assets' || !subSectionFilter ? filter(section.assets) : [];
    const filteredTools = subSectionFilter === 'tools' || !subSectionFilter ? filter(section.tools) : [];
    const filteredScripts = subSectionFilter === 'scripts' || !subSectionFilter ? filter(section.scripts) : [];
    const filteredMaps = subSectionFilter === 'maps' || !subSectionFilter ? filter(section.maps) : [];

    const hasContent = filteredGames.length > 0 || filteredMods.length > 0 || filteredServers.length > 0 || filteredAssets.length > 0 || filteredTools.length > 0 || filteredScripts.length > 0 || filteredMaps.length > 0;

    if (!hasContent && !section.introduction) {
        return (
            <div className="text-center py-20 bg-gray-900/30 rounded-2xl border border-dashed border-white/10">
                <p className="text-gray-500 font-medium italic">This section is currently being curated. Check back soon!</p>
            </div>
        );
    }

    return (
      <div className="space-y-8 mb-12 animate-fade-in-up">
        {title && <h2 className="text-3xl font-bold text-amber-400 mb-4 border-b-2 border-white/10 pb-2">{title}</h2>}

        {section.introduction && !subSectionFilter && (
          <div className="prose prose-invert max-w-none mb-6">
            <MarkdownRenderer markdown={section.introduction} />
          </div>
        )}

        {filteredGames.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Games</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredGames.map(item => <GamingCard key={item.link} item={item} type="game" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredMods.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Mods</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredMods.map(item => <GamingCard key={item.link} item={item} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredServers.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Servers</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredServers.map(item => <GamingCard key={item.link} item={item} type="server" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredAssets.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Assets</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredAssets.map(item => <GamingCard key={item.link} item={{ ...item, genre: [item.type], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredTools.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Tools</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredTools.map(item => <GamingCard key={item.link} item={{ ...item, genre: [item.type || 'Tool'], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredScripts.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Scripts</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredScripts.map(item => <GamingCard key={item.link} item={{ ...item, genre: ['Script'], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
        {filteredMaps.length > 0 && (
          <div><h3 className="text-xl font-bold text-amber-300 mb-4">Maps</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{filteredMaps.map(item => <GamingCard key={item.link} item={{ ...item, genre: ['Map'], platform: [] } as any} type="mod" manifest={manifest} onViewDetails={handleViewDetails} />)}</div></div>
        )}
      </div>
    );
  };

  const renderContent = () => {
    if (!data) return null;

    const navItem = findNavItem(activeTab);

    // 1. Handle Special Tabs
    if (activeTab === GamingSideTab.Introduction) return <IntroductionTab htmlContent={data.intro} newItems={newGamingItems} manifest={manifest} onViewDetails={handleViewDetails} pageType="gaming" />;

    // 2. Handle Dashboard View for Parents
    if (navItem?.children && navItem.children.length > 0) {
        const parentData = getSectionData(activeTab);
        return (
            <CategoryDashboard 
                title={navItem.label}
                subtitle={parentData.summary || `Explore the sub-sections of ${navItem.label}.`}
                items={navItem.children}
                onItemClick={(id) => setActiveTab(id)}
                manifest={manifest}
                dataMapper={(id) => getSectionData(id)}
            />
        );
    }

    // 3. Handle Leaf Nodes
    switch (activeTab) {
        case GamingSideTab.UE5_Games: return renderSection(data.ue5, "UE5 Games", 'games');
        case GamingSideTab.UE5_Assets: return renderSection(data.ue5, "UE5 Assets", 'assets');
        case GamingSideTab.UE5_Tools: return renderSection(data.ue5, "UE5 Tools", 'tools');
        case GamingSideTab.Unity_Games: return renderSection(data.unity, "Unity Games", 'games');
        case GamingSideTab.Unity_Assets: return renderSection(data.unity, "Unity Assets", 'assets');
        case GamingSideTab.Unity_Tools: return renderSection(data.unity, "Unity Tools", 'tools');
        case GamingSideTab.GTA_FiveM_Servers: return renderSection(data.gta?.fivem, "FiveM Servers", 'servers');
        case GamingSideTab.GTA_FiveM_Assets: return renderSection(data.gta?.fivem, "FiveM Assets", 'assets');
        case GamingSideTab.GTA_FiveM_Tools: return renderSection(data.gta?.fivem, "FiveM Tools", 'tools');
        case GamingSideTab.GTA_V_Mods: return renderSection(data.gta?.gta5, "GTA V Mods", 'mods');
        case GamingSideTab.GTA_V_Scripts: return renderSection(data.gta?.gta5, "GTA V Scripts", 'scripts');
        case GamingSideTab.GTA_IV_Mods: return renderSection(data.gta?.iv, "GTA IV Mods", 'mods');
        case GamingSideTab.GTA_IV_Scripts: return renderSection(data.gta?.iv, "GTA IV Scripts", 'scripts');
        case GamingSideTab.Valve_GMod_Mods: return renderSection(data.valve?.gmod, "GMod Mods", 'mods');
        case GamingSideTab.Valve_GMod_Maps: return renderSection(data.valve?.gmod, "GMod Maps", 'maps');
        case GamingSideTab.Valve_Wire_Tools: return renderSection(data.valve?.wire, "Wire Tools", 'tools');
        case GamingSideTab.Valve_Wire_Scripts: return renderSection(data.valve?.wire, "Wire Scripts (E2)", 'scripts');
        case GamingSideTab.Roblox: return renderSection(data.roblox, "Roblox Central");
        case GamingSideTab.Web: return renderSection(data.web, "Web Games");
        case GamingSideTab.Other: return renderSection(data.other, "Miscellaneous");
        default: return null;
    }
  };

  if (!data) return <div className="p-8 text-center text-amber-400 font-bold">Gaming content unavailable.</div>;

  return (
    <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
      <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
        <SideNav<GamingSideTab> tabs={gamingNav} activeTab={activeTab} setActiveTab={setActiveTab} />
      </aside>
      <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
        <div className="px-4 sm:px-6 lg:px-8 pb-28">
          {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default GamingPage;

