              ]
          });
      }

      if (data?.tools?.ai) {
          nav.push({
              id: ToolsSideTab.AITools,
              label: 'AI Hub',
              children: [
                  { id: ToolsSideTab.AI_Apps, label: 'AI Apps' },
                  { id: ToolsSideTab.AI_Prompts, label: 'Prompts' },
              ]
          });
      }

      return nav;
  }, [data]);

  const allTools = useMemo(() => {
    if (!data?.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? [scripts.py, scripts.ps, scripts.ahk].flat().filter(Boolean) : [];
    const aiTools = ai ? [ai.apps, ai.prompts].flat().filter(Boolean) : [];
    return [...web, ...win, ...scriptTools as any, ...aiTools as any].filter(Boolean) as Tool[];
  }, [data]);

  const newToolItems = useMemo(() => {
      return allTools.filter(t => t.new === true);
  }, [allTools]);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  const findNavItem = (id: ToolsSideTab, items: NavItem<ToolsSideTab>[] = dynamicNav): NavItem<ToolsSideTab> | undefined => {
      for (const item of items) {
          if (item.id === id) return item;
          if (item.children) {
              const found = findNavItem(id, item.children);
              if (found) return found;
          }
      }
      return undefined;
  };

  const fetchToolConfig = useCallback(async (link: string): Promise<any> => {
      const cleanLink = link.startsWith('/') ? link.slice(1) : link;
      const candidates = [`/${cleanLink}`];
      if (cleanLink.startsWith('data/')) candidates.push(`/${cleanLink.replace('data/', 'Website/')}`);
      if (cleanLink.startsWith('Website/')) candidates.push(`/${cleanLink.replace('Website/', 'data/')}`);

      for (const url of candidates) {
          try {
              const res = await fetch(url);
              if (res.ok) {
                  const text = await res.text();
                  if (text && text.trim().startsWith('{')) {
                      const json = JSON.parse(text);
                      if (json.category === 'Web Tool' && !json.app_path) continue; 
                      return json;
                  }
              }
          } catch (e) {}
      }

      if (!manifest) throw new Error("Connection Failure: Manifest not loaded.");
      const { user, repo, branch } = manifest.git;
      const remoteContent = await fetchFromGitHubRaw(user, repo, branch, cleanLink);
      return JSON.parse(remoteContent);
  }, [manifest]);

  useEffect(() => {
    if (!selectedItemLink) return;
    const loadDetail = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const detail = await fetchToolConfig(selectedItemLink);
        setDetailData(detail);
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    loadDetail();
  }, [selectedItemLink, fetchToolConfig]);

  const handleViewDetails = useCallback((link: string) => {
    setLaunchedTool(null);
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setLaunchedTool(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    setIsLaunching(true);
    setSelectedItemLink(null); 
    setDetailData(null);
    try {
      const detail = await fetchToolConfig(link);
      if (!detail || !detail.app_path) throw new Error("Metadata Corrupted: Executable path missing.");
      setLaunchedTool(detail as WebToolDetail);
    } catch (err) {
      alert(`Boot Sequence Aborted: ${err instanceof Error ? err.message : 'System Link Error'}`);
    } finally {
      setIsLaunching(false);
    }
  }, [fetchToolConfig]);

  const filteredTools = useMemo(() => {
    if (!data?.tools) return [];
    let sourceTools: Tool[] = [];
    switch (activeTab) {
        case ToolsSideTab.WebTools: sourceTools = data.tools.web || []; break;
        case ToolsSideTab.WindowsTools: sourceTools = data.tools.win || []; break;
        case ToolsSideTab.Scripts_Py: sourceTools = data.tools.scripts?.py || []; break;
        case ToolsSideTab.Scripts_PS: sourceTools = data.tools.scripts?.ps || []; break;
        case ToolsSideTab.Scripts_AHK: sourceTools = data.tools.scripts?.ahk || []; break;
        case ToolsSideTab.AI_Apps: sourceTools = data.tools.ai?.apps || []; break;
        case ToolsSideTab.AI_Prompts: sourceTools = data.tools.ai?.prompts || []; break;
        default: sourceTools = allTools; break;
    }
    return sourceTools
      .filter(tool => showDebugContent || !tool.debug)
      .filter(tool => {
        const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            tool.summary.toLowerCase().includes(searchTerm.toLowerCase());
        const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));
        return searchMatch && tagMatch;
      });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const getSectionData = useCallback((id: ToolsSideTab): any => {
      if (!data?.tools) return {};
      switch (id) {
          case ToolsSideTab.Scripts: return data.tools.scripts;
          case ToolsSideTab.AITools: return data.tools.ai;
          case ToolsSideTab.WebTools: return { name: 'Web Apps', summary: 'Browser-based creative tools.' };
          case ToolsSideTab.WindowsTools: return { name: 'Windows Tools', summary: 'High-performance desktop applications.' };
          case ToolsSideTab.Scripts_Py: return { name: 'Python', summary: 'Powerful backend automation.' };
          case ToolsSideTab.Scripts_PS: return { name: 'PowerShell', summary: 'Windows environment management.' };
          case ToolsSideTab.Scripts_AHK: return { name: 'AutoHotkey', summary: 'Desktop workflow macros.' };
          case GamingSideTab.UE5_Tools: return { name: 'UE5 Tools', summary: 'Game engine utilities.' };
          case ToolsSideTab.AI_Apps: return { name: 'AI Apps', summary: 'Interactive Gen-AI applications.' };
          case ToolsSideTab.AI_Prompts: return { name: 'Prompts', summary: 'Curated resource libraries.' };
          default: return {};
      }
  }, [data]);

  const renderContent = () => {
    if (launchedTool) return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;

    if (selectedItemLink) {
        return <ToolDetailView data={detailData} isLoading={isLoadingDetail} error={detailError} onBack={handleBackToList} onLaunch={() => handleLaunchApp(selectedItemLink)} manifest={manifest} />;
    }

    const navItem = findNavItem(activeTab);

    if (navItem?.children && navItem.children.length > 0) {
        const pData = getSectionData(activeTab);
        return <CategoryDashboard title={navItem.label} subtitle={pData.summary} items={navItem.children} onItemClick={(id) => setActiveTab(id)} manifest={manifest} dataMapper={(id) => getSectionData(id)} />;
    }

    if (activeTab === ToolsSideTab.Introduction) return <IntroductionTab htmlContent={data.intro} newItems={newToolItems} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} pageType="tools" />;

    return (
      <div className="space-y-6">
        <div className="sticky top-2 z-10 flex justify-end">
          <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
            <SearchAndFilter searchTerm={searchTerm} setSearchTerm={setSearchTerm} activeFilter={tagFilter} setActiveFilter={setTagFilter} filterOptions={['All', ...Array.from(new Set(allTools.flatMap(t => t.tags || []))).sort()]} filterTypeLabel="Tag" />
            <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
          </div>
        </div>
        {viewMode === 'card' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredTools.map(item => <ToolCard key={item.link} item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => handleLaunchApp(item.link)} />)}
          </div>
        ) : <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} />}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full py-8">
      {isLaunching && <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center"><div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" /><p className="text-amber-400 font-bold tracking-widest uppercase text-xs animate-pulse">Initializing Production App...</p></div>}
      {!launchedTool && <aside className="w-full md:w-48 lg:w-56 flex-shrink-0"><SideNav<ToolsSideTab> tabs={dynamicNav} activeTab={activeTab} setActiveTab={setActiveTab} /></aside>}
      <div className="flex-grow min-w-0 overflow-y-auto">
        <div className={`px-4 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>{renderContent()}</div>
      </div>
    </div>
  );
};

export default ToolsPage;

// pages/ArtPage.tsx
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ArtPageData, ArtSideTab, NavItem, ArtSection } from '../types';
import { Manifest } from '../services/contentService';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import CategoryDashboard from '../components/CategoryDashboard';
import ArtCard from '../components/art/ArtCard';

interface ArtPageProps {
    data: ArtPageData;
    manifest: Manifest | null;
}

const SESSION_STORAGE_KEY = 'zikyinc_art_active_tab';

const ArtPage: React.FC<ArtPageProps> = ({ data, manifest }) => {
    const [activeTab, setActiveTab] = useState<ArtSideTab>(() => {
        const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
        return (savedTab as ArtSideTab) || ArtSideTab.Introduction;
    });

    useEffect(() => {
        sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    }, [activeTab]);

    /**
     * Build the nav based on what keys exist in the data.
     */
    const artNav = useMemo((): NavItem<ArtSideTab>[] => {
        const nav: NavItem<ArtSideTab>[] = [{ id: ArtSideTab.Introduction, label: 'Introduction' }];
        if (data.canvas_art) nav.push({ id: ArtSideTab.Canvas, label: 'Canvas Art' });
        if (data.street_art) nav.push({ id: ArtSideTab.Street, label: 'Street Art' });
        if (data.digital_art) nav.push({ id: ArtSideTab.Digital, label: 'Digital Art' });
        if (data.artists) nav.push({ id: ArtSideTab.Artists, label: 'Artists' });
        return nav;
    }, [data]);

    const newArtItems = useMemo(() => {
        if (!data) return [];
        const items: any[] = [];
        const filterSection = (section?: ArtSection) => {
            if (!section) return;
            items.push(...(section.pieces || []).filter(p => p.new === true));
            items.push(...(section.list || []).filter(a => a.new === true));
        };
        filterSection(data.canvas_art);
        filterSection(data.street_art);
        filterSection(data.digital_art);
        filterSection(data.artists);
        return items;
    }, [data]);

    const handleViewDetails = (link: string) => {
        console.log('Viewing art details:', link);
    };

    const getSectionData = useCallback((id: ArtSideTab): any => {
        if (!data) return {};
        switch (id) {
            case ArtSideTab.Canvas: return data.canvas_art;
            case ArtSideTab.Street: return data.street_art;
            case ArtSideTab.Digital: return data.digital_art;
            case ArtSideTab.Artists: return data.artists;
            default: return {};
        }
    }, [data]);

    const renderGallery = (section: ArtSection | undefined, title: string, type: 'piece' | 'artist') => {
        if (!section) return null;
        const items = type === 'piece' ? section.pieces : section.list;

        return (
            <div className="animate-fade-in-up space-y-8">
                <header className="border-b border-white/10 pb-6">
                    <h2 className="text-4xl font-extrabold text-amber-400">{title}</h2>
                    {section.summary && <p className="text-gray-400 mt-2 text-lg">{section.summary}</p>}
                </header>

                {section.introduction && (
                    <div className="prose prose-invert max-w-none bg-gray-900/30 p-6 rounded-2xl ring-1 ring-white/5">
                        <IntroductionTab htmlContent={section.introduction} manifest={manifest} />
                    </div>
                )}

                {items && items.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                        {items.map(item => (
                            <ArtCard key={item.link} item={item as any} type={type} manifest={manifest} onViewDetails={handleViewDetails} />
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-20 bg-gray-900/30 rounded-2xl border border-dashed border-white/10">
                        <p className="text-gray-500 italic">No items currently on display in this gallery.</p>
                    </div>
                )}
            </div>
        );
    };

    const renderContent = () => {
        if (!data) return null;

        if (activeTab === ArtSideTab.Introduction) {
            const galleryItems = artNav.filter(n => n.id !== ArtSideTab.Introduction);
            return (
                <div className="space-y-12">
                    <IntroductionTab htmlContent={data.intro} newItems={newArtItems} manifest={manifest} onViewDetails={handleViewDetails} pageType="art" />
                    <CategoryDashboard 
                        title="Gallery Aisles"
                        subtitle="Explore our visual collections by medium and artist."
                        items={galleryItems}
                        onItemClick={(id) => setActiveTab(id)}
                        manifest={manifest}
                        dataMapper={(id) => getSectionData(id)}
                    />
                </div>
            );
        }

        switch (activeTab) {
            case ArtSideTab.Canvas: return renderGallery(data.canvas_art, "The Canvas Gallery", 'piece');
            case ArtSideTab.Street: return renderGallery(data.street_art, "Street & Urban Works", 'piece');
            case ArtSideTab.Digital: return renderGallery(data.digital_art, "The Digital Frontier", 'piece');
            case ArtSideTab.Artists: return renderGallery(data.artists, "Resident Artists", 'artist');
            default: return null;
        }
    };

    if (!data) return <div className="p-8 text-center text-amber-400 font-bold">Art content unavailable.</div>;

    return (
        <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
            <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
                <SideNav<ArtSideTab> tabs={artNav} activeTab={activeTab} setActiveTab={setActiveTab} />
            </aside>
            <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
                <div className="px-4 sm:px-6 lg:px-8 pb-28">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};

export default ArtPage;

// pages/CommunityPage.tsx
import React, { useState, useEffect, useMemo } from 'react';
import { CommunityPageData, CommunitySideTab, CommunityPerson, CommunityEvent } from '../types';
import { Manifest } from '../services/contentService';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import CommunityCard from '../components/community/CommunityCard';

interface CommunityPageProps {
  data: CommunityPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const sideTabs: CommunitySideTab[] = [
  CommunitySideTab.Introduction,
  CommunitySideTab.People,
  CommunitySideTab.Events,
];

const SESSION_STORAGE_KEY = 'zikyinc_community_active_tab';

const CommunityPage: React.FC<CommunityPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<CommunitySideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    if (savedTab && Object.values(CommunitySideTab).includes(savedTab as CommunitySideTab)) {
        return savedTab as CommunitySideTab;
    }
    return CommunitySideTab.Introduction;
  });

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const newCommunityItems = useMemo(() => {
      if (!data) return [];
      const items: any[] = [];
      items.push(...(data.people || []).filter(p => p.new === true));
      items.push(...(data.events || []).filter(e => e.new === true));
      return items;
  }, [data]);

  if (!data) {
    return (
      <div className="p-8 text-center text-amber-400">
        <h2 className="text-2xl font-bold">Community page content is not available.</h2>
      </div>
    );
  }

  const handleViewDetails = (link: string) => {
    console.log('Viewing details for:', link);
  };

  const filteredPeople = useMemo(() => {
    return (data.people || []).filter(person => showDebugContent || !person.debug);
  }, [data.people, showDebugContent]);

  const filteredEvents = useMemo(() => {
    return (data.events || []).filter(event => showDebugContent || !event.debug);
  }, [data.events, showDebugContent]);

  const renderContent = () => {
    switch (activeTab) {
      case CommunitySideTab.Introduction:
        return <IntroductionTab htmlContent={data.introduction || (data as any).intro || ''} newItems={newCommunityItems} manifest={manifest} onViewDetails={handleViewDetails} pageType="community" />;

      case CommunitySideTab.People:
        return (
          <div className="space-y-6">
            <h2 className="text-3xl font-bold text-amber-300 mb-4 border-b-2 border-white/10 pb-2">Our People</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredPeople.map(person => (
                <CommunityCard key={person.link} item={person} type="person" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        );

      case CommunitySideTab.Events:
        return (
          <div className="space-y-6">
            <h2 className="text-3xl font-bold text-amber-300 mb-4 border-b-2 border-white/10 pb-2">Upcoming Events</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredEvents.map(event => (
                <CommunityCard key={event.link} item={event} type="event" manifest={manifest} onViewDetails={handleViewDetails} />
              ))}
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
      <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
        <SideNav<CommunitySideTab> tabs={sideTabs} activeTab={activeTab} setActiveTab={setActiveTab} />
      </aside>
      <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
        <div className="px-4 sm:px-6 lg:px-8 pb-28">
          {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default CommunityPage;

