// pages/ToolsPage.tsx
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { ToolsPageData, ToolsSideTab, Tool, ToolDetail, WebToolDetail, NavItem, GamingSideTab } from '../types';
import { Manifest } from '../services/contentService';
import { fetchFromGitHubRaw } from '../modules/io/import-utils';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import SearchAndFilter from '../components/SearchAndFilter';
import ViewSwitcher, { ViewMode } from '../components/ViewSwitcher';
import ToolCard from '../components/tools/ToolCard';
import ToolDetailView from '../components/tools/ToolDetailView';
import ListView from '../components/music/ListView';
import ToolLauncher from '../components/tools/ToolLauncher';
import CategoryDashboard from '../components/CategoryDashboard';

interface ToolsPageProps {
  data: ToolsPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const SESSION_STORAGE_KEY = 'zikyinc_tools_active_tab';

const ToolsPage: React.FC<ToolsPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<ToolsSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    return (savedTab as ToolsSideTab) || ToolsSideTab.Introduction;
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [tagFilter, setTagFilter] = useState('All');
  const [viewMode, setViewMode] = useState<ViewMode>('card');

  const [selectedItemLink, setSelectedItemLink] = useState<string | null>(null);
  const [detailData, setDetailData] = useState<ToolDetail | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  const [launchedTool, setLaunchedTool] = useState<WebToolDetail | null>(null);
  const [isLaunching, setIsLaunching] = useState(false);

  /**
   * Build the navigation tree dynamically from the JSON
   */
  const dynamicNav = useMemo((): NavItem<ToolsSideTab>[] => {
      const nav: NavItem<ToolsSideTab>[] = [
          { id: ToolsSideTab.Introduction, label: 'Introduction' },
          { id: ToolsSideTab.AllTools, label: 'All Tools' },
          { id: ToolsSideTab.WebTools, label: 'Web Apps' },
          { id: ToolsSideTab.WindowsTools, label: 'Windows Tools' },
      ];

      if (data?.tools?.scripts) {
          nav.push({
              id: ToolsSideTab.Scripts,
              label: 'Scripts',
              children: [
                  { id: ToolsSideTab.Scripts_Py, label: 'Python' },
                  { id: ToolsSideTab.Scripts_PS, label: 'PowerShell' },
                  { id: ToolsSideTab.Scripts_AHK, label: 'AutoHotkey' },
              ]
          });
      }

      if (data?.tools?.ai) {
          nav.push({
              id: ToolsSideTab.AITools,
              label: 'AI Hub',
              children: [
                  { id: ToolsSideTab.AI_Apps, label: 'AI Apps' },
                  { id: ToolsSideTab.AI_Prompts, label: 'Prompts' },
              ]
          });
      }

      return nav;
  }, [data]);

  const allTools = useMemo(() => {
    if (!data?.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? [scripts.py, scripts.ps, scripts.ahk].flat().filter(Boolean) : [];
    const aiTools = ai ? [ai.apps, ai.prompts].flat().filter(Boolean) : [];
    return [...web, ...win, ...scriptTools as any, ...aiTools as any].filter(Boolean) as Tool[];
  }, [data]);

  const newToolItems = useMemo(() => {
      // Fix: Property 'new' is now recognized thanks to types.ts update
      return allTools.filter(t => t.new === true);
  }, [allTools]);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  const findNavItem = (id: ToolsSideTab, items: NavItem<ToolsSideTab>[] = dynamicNav): NavItem<ToolsSideTab> | undefined => {
      for (const item of items) {
          if (item.id === id) return item;
          if (item.children) {
              const found = findNavItem(id, item.children);
              if (found) return found;
          }
      }
      return undefined;
  };

  const fetchToolConfig = useCallback(async (link: string): Promise<any> => {
      const cleanLink = link.startsWith('/') ? link.slice(1) : link;
      const candidates = [`/${cleanLink}`];
      if (cleanLink.startsWith('data/')) candidates.push(`/${cleanLink.replace('data/', 'Website/')}`);
      if (cleanLink.startsWith('Website/')) candidates.push(`/${cleanLink.replace('Website/', 'data/')}`);

      for (const url of candidates) {
          try {
              const res = await fetch(url);
              if (res.ok) {
                  const text = await res.text();
                  if (text && text.trim().startsWith('{')) {
                      const json = JSON.parse(text);
                      if (json.category === 'Web Tool' && !json.app_path) continue; 
                      return json;
                  }
              }
          } catch (e) {}
      }

      if (!manifest) throw new Error("Connection Failure: Manifest not loaded.");
      const { user, repo, branch } = manifest.git;
      const remoteContent = await fetchFromGitHubRaw(user, repo, branch, cleanLink);
      return JSON.parse(remoteContent);
  }, [manifest]);

  useEffect(() => {
    if (!selectedItemLink) return;
    const loadDetail = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const detail = await fetchToolConfig(selectedItemLink);
        setDetailData(detail);
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    loadDetail();
  }, [selectedItemLink, fetchToolConfig]);

  const handleViewDetails = useCallback((link: string) => {
    setLaunchedTool(null);
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setLaunchedTool(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    setIsLaunching(true);
    setSelectedItemLink(null); 
    setDetailData(null);
    try {
      const detail = await fetchToolConfig(link);
      if (!detail || !detail.app_path) throw new Error("Metadata Corrupted: Executable path missing.");
      setLaunchedTool(detail as WebToolDetail);
    } catch (err) {
      alert(`Boot Sequence Aborted: ${err instanceof Error ? err.message : 'System Link Error'}`);
    } finally {
      setIsLaunching(false);
    }
  }, [fetchToolConfig]);

  const filteredTools = useMemo(() => {
    if (!data?.tools) return [];
    let sourceTools: Tool[] = [];
    switch (activeTab) {
        case ToolsSideTab.WebTools: sourceTools = data.tools.web || []; break;
        case ToolsSideTab.WindowsTools: sourceTools = data.tools.win || []; break;
        case ToolsSideTab.Scripts_Py: sourceTools = data.tools.scripts?.py || []; break;
        case ToolsSideTab.Scripts_PS: sourceTools = data.tools.scripts?.ps || []; break;
        case ToolsSideTab.Scripts_AHK: sourceTools = data.tools.scripts?.ahk || []; break;
        case ToolsSideTab.AI_Apps: sourceTools = data.tools.ai?.apps || []; break;
        case ToolsSideTab.AI_Prompts: sourceTools = data.tools.ai?.prompts || []; break;
        default: sourceTools = allTools; break;
    }
    return sourceTools
      .filter(tool => showDebugContent || !tool.debug)
      .filter(tool => {
        const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            tool.summary.toLowerCase().includes(searchTerm.toLowerCase());
        const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));
        return searchMatch && tagMatch;
      });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const getSectionData = useCallback((id: ToolsSideTab): any => {
      if (!data?.tools) return {};
      switch (id) {
          case ToolsSideTab.Scripts: return data.tools.scripts;
          case ToolsSideTab.AITools: return data.tools.ai;
          case ToolsSideTab.WebTools: return { name: 'Web Apps', summary: 'Browser-based creative tools.' };
          case ToolsSideTab.WindowsTools: return { name: 'Windows Tools', summary: 'High-performance desktop applications.' };
          case ToolsSideTab.Scripts_Py: return { name: 'Python', summary: 'Powerful backend automation.' };
          case ToolsSideTab.Scripts_PS: return { name: 'PowerShell', summary: 'Windows environment management.' };
          case ToolsSideTab.Scripts_AHK: return { name: 'AutoHotkey', summary: 'Desktop workflow macros.' };
          // Fix: Removed reference to GamingSideTab.UE5_Tools as it is not part of ToolsSideTab enum
          case ToolsSideTab.AI_Apps: return { name: 'AI Apps', summary: 'Interactive Gen-AI applications.' };
          case ToolsSideTab.AI_Prompts: return { name: 'Prompts', summary: 'Curated resource libraries.' };
          default: return {};
      }
  }, [data]);

  const renderContent = () => {
    if (launchedTool) return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;

    if (selectedItemLink) {
        return <ToolDetailView data={detailData} isLoading={isLoadingDetail} error={detailError} onBack={handleBackToList} onLaunch={() => handleLaunchApp(selectedItemLink)} manifest={manifest} />;
    }

    const navItem = findNavItem(activeTab);

    if (navItem?.children && navItem.children.length > 0) {
        const pData = getSectionData(activeTab);
        return <CategoryDashboard title={navItem.label} subtitle={pData.summary} items={navItem.children} onItemClick={(id) => setActiveTab(id)} manifest={manifest} dataMapper={(id) => getSectionData(id)} />;
    }

    if (activeTab === ToolsSideTab.Introduction) return <IntroductionTab htmlContent={data.intro} newItems={newToolItems} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} pageType="tools" />;

    return (
      <div className="space-y-6">
        <div className="sticky top-2 z-10 flex justify-end">
          <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
            <SearchAndFilter searchTerm={searchTerm} setSearchTerm={setSearchTerm} activeFilter={tagFilter} setActiveFilter={setTagFilter} filterOptions={['All', ...Array.from(new Set(allTools.flatMap(t => t.tags || []))).sort()]} filterTypeLabel="Tag" />
            <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
          </div>
        </div>
        {viewMode === 'card' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredTools.map(item => <ToolCard key={item.link} item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => handleLaunchApp(item.link)} />)}
          </div>
        ) : <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} />}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full py-8">
      {isLaunching && <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center"><div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" /><p className="text-amber-400 font-bold tracking-widest uppercase text-xs animate-pulse">Initializing Production App...</p></div>}
      {!launchedTool && <aside className="w-full md:w-48 lg:w-56 flex-shrink-0"><SideNav<ToolsSideTab> tabs={dynamicNav} activeTab={activeTab} setActiveTab={setActiveTab} /></aside>}
      <div className="flex-grow min-w-0 overflow-y-auto">
        <div className={`px-4 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>{renderContent()}</div>
      </div>
    </div>
  );
};

